var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"사장님, 어디 고장난 데 있으십니까?","JPN":"社長、故障してないでしょうか？","ENG":"Boss, how are your functions?","TWN":"老闆，有哪裡壞掉嗎？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"끄응. 괜찮네. 수납함에 바닷물이 들어간 것만 빼고 말이야.","JPN":"ううむ……問題ない。収納箱に海水が入ったこと以外はな。","ENG":"Ugh, they are fine. Except that my cabinet was flooded with sea water.","TWN":"嗯，還好，只是收納箱浸水了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아, 그리고 왠지 몸이 아주 개운하군! 마사지라도 받은 기분이야!","JPN":"あ、でもなんだか身体がとてもスッキリするな！　マッサージでも受けた気分だ！","ENG":"Oh, and I feel great! As if I just had a massage!","TWN":"還有，不知道怎麼搞的，身體滿舒坦的！感覺像剛做完按摩一樣！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"로봇도 근육통이 생기나요. 그런 쓸데없는 기능을 잘도 만들어 두셨군요.","JPN":"ロボットも筋肉痛になるんですか？　そんな無駄な機能をよく作りましたね。","ENG":"I didn’t know robots could feel muscular pain. That’s such a useless feature.","TWN":"機器人也會肌肉酸痛嗎？你連那些莫名其妙的功能也有做喔？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어허, 원래 기술의 발전은 쓸데없어 보이는 곳에서부터 시작하는 법일세.","JPN":"ほら、そもそも技術の発展は無駄なところから始まるものさ。","ENG":"You should know that advance comes from useless features.","TWN":"哎唷，技術的發展本來就是從莫名其妙的地方開始的。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그보다 그 펭귄들은 어떻게 됐나?","JPN":"それより、ペンギンたちはどうなった？","ENG":"By the way, what happened to the penguins?","TWN":"話說回來，那些企鵝怎麼樣了？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"배달부에게 맡겨 뒀습니다. 지금쯤이면 정리가 다 끝났겠죠.","JPN":"配達員に任せました。今頃片付け終わっているでしょう。","ENG":"The deliverywoman is taking care of them. I’m sure she’s done by now.","TWN":"交給送貨員處理了，現在差不多處理得差不多了吧？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네!","JPN":"モネ！　モネ！","ENG":"Mone! Mone!","TWN":"莫妮！莫妮！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모~네!","JPN":"モ～ネ！","ENG":"Mo-ne!","TWN":"莫～妮！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"잠깐만요! 펭귄님들! 아무리 배달에 불만이 있어도 사람을 물에 던지면 안 되죠!","JPN":"待ってください、ペンギン様！　いくら配達に不満があっても人を海に投げ落としてはいけませんよ！","ENG":"Hey, wait! My dear penguins! You should not throw a delivery person to the sea, even if you have a problem with the delivery!","TWN":"等一下！企鵝們！就算要客訴，也不能把人扔進水裡吧！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗! 잠깐만요, 스톱! 타임!","JPN":"あっ、待って！　ストップ！　ストップ！","ENG":"Oh! Wait! Stop! Time out!","TWN":"哎唷！等一下，停！暫停！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자기가 정리를 당했구만.","JPN":"片付けられたのは本人だったな。","ENG":"I see the deliverywoman has been taken care of.","TWN":"看來是她被企鵝處理。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh*","TWN":"哎…"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"저 펭귄들, 우리가 여기 있는 게 마음에 안 들어서 저러는 걸까?","JPN":"あのペンギンたち、私たちがここにいるのが気に食わなくてあんなことをしているのかね。","ENG":"Do you think they are acting like that because they don’t want us here?","TWN":"那些企鵝是因爲不喜歡我們在這裡才那樣嗎？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"이유야 아무래도 좋습니다. 휴가를 망치는 방해꾼들이란 사실은 변함없으니까요.","JPN":"理由はどうでもいいです。休みを台無しにする邪魔者という事実は変わりません。","ENG":"Who cares. What’s important is that they are ruining my vacation.","TWN":"理由不管是什麼，都不會改變他們毀掉假期的事實。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"적당히 겁을 줘서 쫓아내겠습니다. 사장님은 잠시 물러나 계세요.","JPN":"適当に脅して追い払います。社長は下がっていてください。","ENG":"I’ll just scare them away. Boss, please stay back.","TWN":"我會稍微教訓一下他們，把他們趕走。老闆請先迴避。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"잠깐 기다려 보게. 싸움이 언제나 좋은 해결책인 건…….","JPN":"待ってくれ。戦いが最善の解決策になるとは限らな……","ENG":"Wait. Fighting is not the solution for everything—","TWN":"請稍等一下。不要老是動不動就要動手……"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};